const numbers = [1, 2, 3, 4, 5];

// Double every number
const doubled = numbers.map(n => n * 2);

console.log(doubled);  // [2, 4, 6, 8, 10]
console.log(numbers);  // [1, 2, 3, 4, 5]  — original unchanged

const fruits = ['apple', 'banana', 'cherry'];

const labeled = fruits.map((fruit, index) => `${index + 1}. ${fruit}`);

console.log(labeled);
// ['1. apple', '2. banana', '3. cherry']

// What map() does internally (simplified)
function myMap(array, callback) {
  const result = [];
  for (let i = 0; i < array.length; i++) {
    result.push(callback(array[i], i, array));
  }
  return result;
}

const doubled = myMap([1, 2, 3], n => n * 2);
console.log(doubled); // [2, 4, 6]

const nums = [1, 2, 3];

// map — produces a value
const squares = nums.map(n => n * n); // [1, 4, 9]

// forEach — produces nothing, used for side effects
nums.forEach(n => console.log(n));    // logs 1, 2, 3 → returns undefined

const cities = ['Tokyo', 'Paris', 'New York', 'Sydney'];

function CityList() {
  return (
    <ul>
      {cities.map((city, index) => (
        <li key={index}>{city}</li>
      ))}
    </ul>
  );
}

const users = [
  { id: 1, name: 'Alice' },
  { id: 2, name: 'Bob' },
  { id: 3, name: 'Carol' },
];

function UserList() {
  return (
    <ul>
      {users.map(user => (
        <li key={user.id}>{user.name}</li>  // ✅ stable id as key
      ))}
    </ul>
  );
}

const products = [
  { id: 'p1', name: 'Keyboard', price: 79 },
  { id: 'p2', name: 'Monitor',  price: 299 },
  { id: 'p3', name: 'Webcam',   price: 59 },
];

function ProductList() {
  return (
    <div className="products">
      {products.map(({ id, name, price }) => (
        <div key={id} className="product-card">
          <h3>{name}</h3>
          <p>${price}</p>
        </div>
      ))}
    </div>
  );
}

function ActiveUserList({ users }) {
  return (
    <ul>
      {users
        .filter(user => user.isActive)       // keep only active users
        .map(user => (                         // transform each to JSX
          <li key={user.id}>{user.name}</li>
        ))
      }
    </ul>
  );
}

// ❌ Arrow function with a block body requires an explicit return
const items = [1, 2, 3].map(n => {
  n * 2;  // no return — result is undefined
});
console.log(items); // [undefined, undefined, undefined]

// ✅ Concise body (implicit return)
const items2 = [1, 2, 3].map(n => n * 2);

// ✅ Block body with explicit return
const items3 = [1, 2, 3].map(n => {
  return n * 2;
});

// ❌ Block body, no return — renders nothing
users.map(user => {
  <li key={user.id}>{user.name}</li>
})

// ✅ Concise body (implicit return) — use parentheses for multi-line JSX
users.map(user => (
  <li key={user.id}>{user.name}</li>
))

// ✅ Block body with explicit return
users.map(user => {
  return <li key={user.id}>{user.name}</li>;
})

// ❌ No key — React warning, potential rendering bugs
items.map(item => <li>{item.name}</li>)

// ❌ Index as key on a dynamic list — causes incorrect updates on reorder
items.map((item, i) => <li key={i}>{item.name}</li>)

// ✅ Stable, unique ID from the data
items.map(item => <li key={item.id}>{item.name}</li>)

const users = [{ name: 'Alice', score: 10 }];

// ❌ Mutating the original object — modifies the source array's element
const updated = users.map(user => {
  user.score += 5;  // mutates original
  return user;
});

// ✅ Return a new object — leave the original untouched
const updated2 = users.map(user => ({ ...user, score: user.score + 5 }));

function renderUserRow(user) {
  return (
    <tr key={user.id}>
      <td>{user.name}</td>
      <td>{user.email}</td>
    </tr>
  );
}

// Clean call site
function UserTable({ users }) {
  return <tbody>{users.map(renderUserRow)}</tbody>;
}
